/** Low-level HTTP helpers. */

export class HttpError extends Error {
  constructor(public status: number, message: string) {
    super(message);
    this.name = 'HttpError';
  }
}

export async function request<T>(url: string, init?: RequestInit): Promise<T> {
  const response = await fetch(url, init);
  if (!response.ok) {
    throw new HttpError(response.status, `request failed: ${response.status} ${url}`);
  }
  return (await response.json()) as T;
}

const RETRYABLE = new Set([429, 502, 503, 504]);

/** Like request(), but retries transient failures with exponential backoff. */
export async function fetchWithRetry<T>(url: string, init?: RequestInit, attempts = 3): Promise<T> {
  let lastError: unknown;
  for (let attempt = 0; attempt < attempts; attempt += 1) {
    try {
      return await request<T>(url, init);
    } catch (error) {
      lastError = error;
      const retryable = error instanceof HttpError && RETRYABLE.has(error.status);
      if (!retryable && !(error instanceof TypeError)) {
        throw error;
      }
      await new Promise((resolve) => setTimeout(resolve, 250 * 2 ** attempt));
    }
  }
  throw new Error(`request failed after ${attempts} retries: ${url}`, { cause: lastError });
}

"""Tiny in-memory TTL cache used for hot lookups (e.g. users by id)."""

import time
from typing import Any, Callable


class MemoCache:
    """Dict-backed cache with per-entry expiry. Not thread-safe."""

    def __init__(self, ttl_seconds: float = 60.0, clock: Callable[[], float] = time.monotonic) -> None:
        self.ttl = ttl_seconds
        self._clock = clock
        self._entries: dict[Any, tuple[float, Any]] = {}

    def get(self, key: Any) -> Any | None:
        entry = self._entries.get(key)
        if entry is None:
            return None
        expires_at, value = entry
        if self._clock() >= expires_at:
            del self._entries[key]
            return None
        return value

    def put(self, key: Any, value: Any) -> None:
        self._entries[key] = (self._clock() + self.ttl, value)

    def clear(self) -> None:
        self._entries.clear()

